output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?book ?date WHERE {
  {
    wd:Q752584 wdt:P577 ?date .
    BIND(wd:Q752584 AS ?book)
  } UNION {
    wd:Q478016 wdt:P577 ?date .
    BIND(wd:Q478016 AS ?book)
  }
}
ORDER BY ?date
LIMIT 1

